//! Single-include amalgamation header(s).
//!
//! For internal cheats it's enormously useful to have one file you can
//! `#include` (or one Rust module you can copy in) that pulls in
//! offsets + interfaces + netvars + signatures + the SDK macros all at
//! once.
//!
//! This module emits:
//!
//! - `cs2sdk.hpp` — single-include C++ amalgamation
//! - `cs2sdk.rs`  — single-file Rust module
//!
//! Both are *idempotent* — they only re-export what other emitters in
//! this run produced, they don't duplicate any data.
//!
//! ## Design choice: `#include`s vs amalgamation
//!
//! We deliberately use `#include` rather than concatenating every file's
//! contents into one mega-file. That keeps:
//!
//! 1. compile times low (the user only pays for what they touch),
//! 2. error messages pointing at the right file, and
//! 3. diffs between two builds clean.

/// Render a single-include C++ header.
///
/// `sdk_modules` is the list of module file stems that the SDK class
/// emitter wrote (e.g. `["client_dll", "engine2_dll"]`).
pub fn render_hpp(sdk_modules: &[String], build_number: Option<u32>) -> String {
    let mut s = String::new();
    s.push_str("// Auto-generated by cs2-universal-dumper. Do not edit.\n");
    s.push_str("//\n");
    s.push_str("// Single-include amalgamation header for CS2 internal cheats.\n");
    s.push_str("//\n");
    s.push_str("// Drop the `signatures/` and `sdk/` folders into your project,\n");
    s.push_str("// add this file's directory to your include path, and:\n");
    s.push_str("//\n");
    s.push_str("//     #include \"cs2sdk.hpp\"\n");
    s.push_str("//\n");
    s.push_str("// gets you offsets, interfaces, netvars, signatures, and SDK classes.\n\n");
    s.push_str("#pragma once\n\n");
    if let Some(bn) = build_number {
        s.push_str("namespace cs2 {\n");
        s.push_str(&format!("    inline constexpr unsigned int CS2_BUILD = {bn};\n"));
        s.push_str("}\n\n");
    }
    s.push_str("// SDK macros (SCHEMA_FIELD, field_ref<T>, ...)\n");
    s.push_str("#include \"sdk/cs2sdk_macros.hpp\"\n\n");
    s.push_str("// Per-module schema classes\n");
    for m in sdk_modules {
        s.push_str(&format!("#include \"sdk/{}.hpp\"\n", m));
    }
    s.push('\n');
    s.push_str("// Resolved interfaces, netvars, signatures\n");
    s.push_str("#include \"interfaces.hpp\"\n");
    s.push_str("#include \"netvars.hpp\"\n");
    s.push_str("#include \"signatures.hpp\"\n");
    s
}

/// Render a single-file Rust module that re-exports every emitted
/// `*.rs` consumer file.
pub fn render_rs(sig_modules_present: bool, build_number: Option<u32>) -> String {
    let mut s = String::new();
    s.push_str("// Auto-generated by cs2-universal-dumper. Do not edit.\n");
    s.push_str("//\n");
    s.push_str("// Single-file Rust amalgamation. Drop alongside the emitted\n");
    s.push_str("// `*.rs` files and add `mod cs2sdk;` to your crate.\n\n");
    s.push_str("#![allow(non_upper_case_globals, non_snake_case, dead_code)]\n\n");
    if let Some(bn) = build_number {
        s.push_str(&format!("pub const CS2_BUILD: u32 = {bn};\n\n"));
    }
    if sig_modules_present {
        s.push_str("#[path = \"signatures.rs\"] pub mod signatures;\n");
    }
    s.push_str("// Per-module offsets are emitted as <module>.rs by the offset pass.\n");
    s.push_str("// Re-export them here as you need; example:\n");
    s.push_str("//   #[path = \"client_dll.rs\"] pub mod client_dll;\n");
    s
}
